Here's a minimal API endpoint handling multipart form uploads with multiple images and a description:

```csharp
using Microsoft.AspNetCore.Http.Features;

var builder = WebApplication.CreateBuilder(args);

// Raise the max request body size to 50 MB
builder.WebHost.ConfigureKestrel(o =>
    o.Limits.MaxRequestBodySize = 50 * 1024 * 1024);

var app = builder.Build();

app.MapPost("/upload", async (HttpRequest request) =>
{
    // Read the multipart form; set the same 50 MB limit on buffering
    var form = await request.ReadFormAsync(new FormOptions
    {
        MultipartBodyLengthLimit = 50 * 1024 * 1024
    });

    var description = form["description"].ToString();
    var files = form.Files.GetFiles("images");   // matches <input name="images">

    if (files.Count == 0)
        return Results.BadRequest("No images provided.");

    var saved = new List<string>();

    foreach (var file in files)
    {
        // Validate content type
        if (!file.ContentType.StartsWith("image/"))
            return Results.BadRequest($"'{file.FileName}' is not an image.");

        var dest = Path.Combine("uploads", $"{Guid.NewGuid()}{Path.GetExtension(file.FileName)}");
        Directory.CreateDirectory("uploads");

        await using var stream = File.Create(dest);
        await file.CopyToAsync(stream);
        saved.Add(dest);
    }

    return Results.Ok(new { description, uploadedFiles = saved });
})
.DisableAntiforgery();   // needed for anonymous form POSTs in .NET 8+

app.Run();
```

**Key points:**

- **Two size limits** — `Kestrel.MaxRequestBodySize` gates the raw request; `FormOptions.MultipartBodyLengthLimit` gates form parsing. Both must be ≥ 50 MB.
- **`DisableAntiforgery()`** — .NET 8 enables antiforgery for form-bound endpoints by default. Remove this call if you add token validation.
- **`form.Files.GetFiles("images")`** — pulls all files with that form field name; use `form.Files` to grab everything regardless of name.

A matching `curl` test:

```bash
curl -X POST http://localhost:5000/upload \
  -F "description=My photos" \
  -F "images=@photo1.jpg" \
  -F "images=@photo2.png"
```
